11→export function ToastContainer({
12→  toasts,
13→  onDismiss,
14→  portalTarget,
15→}: ToastContainerProps) {
16→  if (toasts.length === 0) return null;
17→
18→  const content = (
19→    <div className="toast-container">
20→      {toasts.map(toast => (
21→        <Toast
22→          key={toast.id}
23→          style={toast.style}
24→          title={toast.title}
25→          message={toast.message}
26→          onDismiss={() => onDismiss(toast.id)}
