 1→import { useCallback, useRef, useState } from 'react';
 2→import type { ToastData, ToastStyle } from '../components/toast/toast';
 3→
 4→let nextId = 0;
 5→
 6→interface ShowToastOptions {
 7→  style?: ToastStyle;
 8→  title: string;
 9→  message?: string;
10→}
11→
12→export function useToast() {
13→  const [toasts, setToasts] = useState<ToastData[]>([]);
14→  const timersRef = useRef<Map<string, ReturnType<typeof setTimeout>>>(
15→    new Map(),
16→  );
17→
18→  const hide = useCallback((id: string) => {
19→    const timer = timersRef.current.get(id);
20→    if (timer) {
21→      clearTimeout(timer);
22→      timersRef.current.delete(id);
23→    }
24→    setToasts(prev => prev.filter(t => t.id !== id));
25→  }, []);
26→
27→  const show = useCallback((options: ShowToastOptions) => {
28→    const id = String(nextId++);
29→    const toast: ToastData = {
30→      id,
31→      style: options.style ?? 'info',
32→      title: options.title,
33→      message: options.message,
34→    };
35→
36→    setToasts(prev => [
37→      ...prev,
38→      toast,
39→    ]);
40→
41→    const timer = setTimeout(() => {
42→      timersRef.current.delete(id);
43→      setToasts(prev => prev.filter(t => t.id !== id));
44→    }, 3000);
45→    timersRef.current.set(id, timer);
46→
47→    return id;
48→  }, []);
49→
50→  return {
51→    toasts,
52→    show,
53→    hide,
54→  };
55→}
