 94→export function App() {
 95→  const [query, setQuery] = useState('');
 96→  const [selectedIndex, setSelectedIndex] = useState(0);
 97→  const [actionsOpen, setActionsOpen] = useState(false);
 98→  const [drilledItem, setDrilledItem] = useState<ListItemData | null>(null);
 99→  const { toasts, show: showToast, hide: hideToast } = useToast();
100→
101→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
102→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
103→  const selectedItem = drilledItem ?? allItems[selectedIndex];
104→
105→  const handleQueryChange = useCallback((value: string) => {
106→    setQuery(value);
107→    setSelectedIndex(0);
108→    setActionsOpen(false);
109→  }, []);
110→
111→  const handleActiveIndexChange = useCallback((index: number) => {
112→    setSelectedIndex(index);
113→    setActionsOpen(false);
114→  }, []);
115→
116→  const handleDrillIn = useCallback(() => {
117→    const item = allItems[selectedIndex];
118→    if (item) {
119→      setDrilledItem(item);
120→      setQuery('');
121→      setActionsOpen(false);
122→      showToast({
123→        style: 'success',
124→        title: `Opened ${item.title}`,
125→      });
126→    }
127→  }, [
128→    allItems,
129→    selectedIndex,
130→    showToast,
131→  ]);
132→
133→  const handleDrillBack = useCallback(() => {
134→    setDrilledItem(null);
135→    setQuery('');
136→    setSelectedIndex(0);
137→    setActionsOpen(false);
138→  }, []);
139→
140→  const breadcrumbs: BreadcrumbItem[] | undefined = drilledItem
141→    ? [
142→        {
143→          label: 'Raycast',
144→          onBack: handleDrillBack,
145→        },
146→        {
147→          label: drilledItem.title,
148→        },
149→      ]
150→    : undefined;
151→
152→  const toggleActions = useCallback(() => {
153→    setActionsOpen(prev => !prev);
154→  }, []);
155→
156→  const closeActions = useCallback(() => {
157→    setActionsOpen(false);
158→  }, []);
159→
160→  useEffect(() => {
161→    function handleKeyDown(e: KeyboardEvent) {
162→      if (e.key === 'k' && e.metaKey) {
163→        e.preventDefault();
164→        setActionsOpen(prev => !prev);
165→      }
166→    }
167→
168→    window.addEventListener('keydown', handleKeyDown);
169→    return () => window.removeEventListener('keydown', handleKeyDown);
170→  }, []);
171→
172→  const detail = selectedItem?.detail;
173→
174→  const dropdownActions = useMemo(
175→    () => [
176→      {
177→        label: 'Open',
178→        shortcut: <Kbd keys={['↵']} />,
179→      },
180→      {
181→        label: 'Copy Name',
182→        shortcut: (
183→          <Kbd
184→            keys={[
185→              '⌘',
186→              'C',
187→            ]}
188→          />
189→        ),
190→      },
191→      {
192→        label: 'Show Detail',
193→        shortcut: (
194→          <Kbd
195→            keys={[
196→              '⌘',
197→              'D',
198→            ]}
199→          />
200→        ),
201→      },
202→      {
203→        label: 'Pin to Top',
204→        shortcut: (
205→          <Kbd
206→            keys={[
207→              '⌘',
208→              'P',
209→            ]}
210→          />
211→        ),
212→      },
213→    ],
214→    [],
215→  );
216→
217→  return (
218→    <CommandPalette isLoading>
219→      <SearchBar
220→        value={query}
221→        onChange={handleQueryChange}
222→        activeDescendantId={
223→          allItems.length > 0 ? `list-item-${selectedIndex}` : undefined
224→        }
225→        breadcrumbs={breadcrumbs}
226→      />
227→      <div
228→        className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
229→      >
230→        <div className="command-palette__list-container">
231→          {allItems.length === 0 ? (
232→            <EmptyState
233→              icon={<SearchIcon />}
234→              title="No Results"
235→              description="Try a different search term"
236→            />
237→          ) : (
238→            <List
239→              itemCount={allItems.length}
240→              onActiveIndexChange={handleActiveIndexChange}
241→              onAction={handleDrillIn}
242→            >
243→              {(() => {
244→                let globalIndex = 0;
245→                return filtered.map(section => (
246→                  <ListSection key={section.title} title={section.title}>
247→                    {section.items.map(item => {
248→                      const idx = globalIndex++;
249→                      return (
250→                        <ListItem
251→                          key={item.id}
252→                          index={idx}
253→                          title={item.title}
254→                          subtitle={item.subtitle}
255→                          icon={item.icon}
256→                          accessories={item.accessories}
257→                        />
258→                      );
259→                    })}
260→                  </ListSection>
261→                ));
262→              })()}
263→            </List>
264→          )}
265→        </div>
266→        {detail && (
267→          <Detail
268→            markdown={detail.markdown}
269→            metadata={
270→              detail.metadata ? (
271→                <DetailMetadata>
272→                  {detail.metadata.map(renderMetadataEntry)}
273→                </DetailMetadata>
274→              ) : undefined
275→            }
276→          />
277→        )}
278→      </div>
279→      <ActionPanel
280→        actions={[
281→          {
282→            label: 'Open',
283→            shortcut: <Kbd keys={['↵']} />,
284→          },
285→          {
286→            label: 'Actions',
287→            shortcut: (
288→              <Kbd
289→                keys={[
290→                  '⌘',
291→                  'K',
292→                ]}
293→              />
294→            ),
295→            onClick: toggleActions,
296→          },
297→        ]}
298→        dropdownOpen={actionsOpen}
299→        dropdownActions={dropdownActions}
300→        onDropdownClose={closeActions}
301→      />
302→      <ToastContainer toasts={toasts} onDismiss={hideToast} />
303→    </CommandPalette>
304→  );
305→}
